SELECT /* @SQLID=SUB0401_01-01#Sql002 */ N.COUNT AS totalCount, N.COR_TITLE AS title, N.EMPLOYEE_ID AS employeeId, N.USER_NM AS userId, N.BRANCH_NAME AS brokerBranchName, N.COR_CONFIRMATION_DATE AS confirmDateTime, N.CODE_NAME AS codeName, N.BROKER_ID AS brokerCode, N.COR_BROWSE_FLAG AS corBrowseFlag FROM ( SELECT COUNT(*) OVER() AS COUNT, M.COR_TITLE, M.EMPLOYEE_ID, M.USER_NM, M.BRANCH_NAME, A.COR_CONFIRMATION_DATE, CM.CODE_NAME, M.BROKER_ID, C.COR_BROWSE_FLAG FROM ( SELECT MU.USER_ID, MU.EMPLOYEE_ID, MU.USER_NM, MU.BROKER_ID, MU.SUB_BROKER_ID, CC.COR_LEC_ID, CC.COR_TITLE, CC.COR_COMMUNICATION_DATE, MB.BRANCH_NAME FROM COR_COMPLIANCE_COMMUNICATION CC, TB_MED_USERS MU
INNER JOIN MEDIATE_BRANCH MB ON MU.BROKER_ID = MB.BROKER_CODE AND MB.BROKER_BRANCH_KIND = '00' AND UTL_I18N.TRANSLITERATE(UPPER(TO_MULTI_BYTE(MB.BRANCH_NAME)),'kana_fwkatakana') LIKE '%'|| UTL_I18N.TRANSLITERATE(UPPER(TO_MULTI_BYTE(#{req.brokerName})), 'kana_fwkatakana')||'%'
LEFT JOIN MEDIATE_BRANCH MB ON MU.BROKER_ID = MB.BROKER_CODE AND MB.BROKER_BRANCH_KIND = '00'
WHERE MU.PRIV_ID <> '1' AND MU.PRIV_ID <> '2' AND (
CC.COR_COMMUNICATION_DATE > (SELECT TO_CHAR(IFA_DATE_UTIL.IFA_GET_DATE - INTERVAL '5' YEAR,'YYYYMM') FROM DUAL) AND CC.COR_COMMUNICATION_DATE <= (SELECT TO_CHAR(IFA_DATE_UTIL.IFA_GET_DATE,'YYYYMM') FROM DUAL)
CC.COR_COMMUNICATION_DATE > (SELECT TO_CHAR(IFA_DATE_UTIL.IFA_GET_DATE - INTERVAL '5' YEAR,'YYYYMM') FROM DUAL) AND CC.COR_COMMUNICATION_DATE < (SELECT TO_CHAR(IFA_DATE_UTIL.IFA_GET_DATE,'YYYYMM') FROM DUAL)
CC.COR_COMMUNICATION_DATE = (SELECT TO_CHAR(IFA_DATE_UTIL.IFA_GET_DATE,'YYYYMM') FROM DUAL)
) ) M LEFT JOIN COR_COMPLIANCE_CONFIRMATION A ON M.COR_LEC_ID = A.COR_LEC_ID AND M.USER_ID = A.COR_USER_ID LEFT JOIN COR_BROWSE_CONTROL_INDV C ON M.USER_ID = C.COR_USER_ID LEFT JOIN CORDYS_CODE_MASTER CM ON CM.FUNCTION_ID = '013' AND A.COR_CONFIRMATION_FLG = CM.CODE_ID
M.USER_NM LIKE '%'||#{req.brokerChargeName}||'%'
AND (M.BROKER_ID IN
) OR M.BROKER_ID IN(
,
#{brokerCharge.brokerCode}
)
AND ((M.BROKER_ID, M.EMPLOYEE_ID) IN
) OR (M.BROKER_ID, M.EMPLOYEE_ID) IN(
,
(#{brokerCharge.brokerCode}, #{brokerCharge.empCode})
)
AND M.COR_TITLE = #{req.title}
AND A.COR_CONFIRMATION_FLG = #{req.viewStatus}
AND (A.COR_CONFIRMATION_FLG IS NULL OR A.COR_CONFIRMATION_FLG = #{req.viewStatus})
AND (C.COR_BROWSE_FLAG IS NULL OR C.COR_BROWSE_FLAG = #{req.viewTarget})
AND C.COR_BROWSE_FLAG = #{req.viewTarget}
ORDER BY M.COR_COMMUNICATION_DATE DESC, M.BROKER_ID ) N WHERE 1=1 AND ROWNUM <= #{req.maxRowNum}
